  ('social-worker-moex-02166', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '為了解家長參與小學中家長支持團體活動的經驗，研究者欲採用在旁觀察團體進行的方式進行研究。請 問研究者在此情境中的觀察者身分，是下列四種中的那種身分呢？', '["完全參與者", "參與者就是觀察者", "觀察者就是參與者", "完全觀察者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "88073911b247", "answer_pdf_sha1": "449337010204", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
